using namespace std;

int main() {
    int j;  // 'j' is declared before the loop - its scope continues after the loop
    for (j = 1; j <= 3; j++) {
        cout << "Value of j inside loop: " << j << endl;
    }

    // 'j' is still accessible here
    cout << "Value of j after loop ends: " << j << endl;

    return 0;
}
```
**Expected Output:**
```default
Value of j inside loop: 1
Value of j inside loop: 2
Value of j inside loop: 3
Value of j after loop ends: 4
```

